// Unit test for computeRoutePlan — verifies haversine distance (nm), initial
// bearing/compass, durations, cumulative depart/arrive timing, speed scaling,
// and the null guards for too-few points / non-positive speed.
async function testComputeRoutePlan() {
  const start = 1700000000000; // fixed UTC ms for deterministic timing

  // A due-north leg of exactly 1 degree of latitude (~60 nm) from the equator
  const points = [
    { lat: 0, lon: 0 },
    { lat: 1, lon: 0 },
    { lat: 1, lon: 1 }   // second leg heads roughly east
  ];

  const plan = functions.call('computeRoutePlan', points, 6, start);
  assert(plan && Array.isArray(plan.legs), 'Should return a plan with legs');
  assertEquals(plan.legs.length, 2, 'Three points form two legs');

  // Leg 0: ~60 nm due north
  const leg0 = plan.legs[0];
  assert(leg0.distanceNm >= 59.8 && leg0.distanceNm <= 60.3, 'Leg 0 ~60 nm, got ' + leg0.distanceNm);
  assertEquals(leg0.bearing, 0, 'Due-north bearing should be 0');
  assertEquals(leg0.bearingCompass, 'N', 'Due-north compass should be N');

  // Duration = distance / speed; at 6 kn, ~60 nm ≈ 10 h
  assert(leg0.durationHours >= 9.9 && leg0.durationHours <= 10.1, 'Leg 0 ~10h at 6kn, got ' + leg0.durationHours);

  // Timing: leg 0 departs at start; leg 1 departs when leg 0 arrives
  assertEquals(leg0.departTimeMs, start, 'Leg 0 departs at start time');
  assertEquals(plan.legs[1].departTimeMs, leg0.arriveTimeMs, 'Leg 1 departs when leg 0 arrives');

  // Leg 1 heads roughly east → bearing near 90
  const leg1 = plan.legs[1];
  assert(leg1.bearing > 80 && leg1.bearing < 100, 'Leg 1 heads ~east, got ' + leg1.bearing);

  // Totals aggregate distance/time; ETA equals the final leg's arrival
  assert(plan.totals.distanceNm >= leg0.distanceNm, 'Total distance includes all legs');
  assert(Math.abs(plan.totals.etaMs - leg1.arriveTimeMs) <= 1, 'ETA should match final leg arrival');

  // Speed scaling: doubling speed halves the durations
  const fast = functions.call('computeRoutePlan', points, 12, start);
  assert(Math.abs(fast.totals.durationHours - plan.totals.durationHours / 2) < 0.05,
    'Doubling speed should halve total duration');

  // Null guards
  assertEquals(functions.call('computeRoutePlan', [{ lat: 0, lon: 0 }], 6, start), null, '<2 points returns null');
  assertEquals(functions.call('computeRoutePlan', points, 0, start), null, 'speed 0 returns null');
  assertEquals(functions.call('computeRoutePlan', points, -3, start), null, 'negative speed returns null');
}
